func TestOpenAPISpecValidates(t *testing.T) {
	doc := loadOpenAPIDoc(t)
	if err := doc.Validate(context.Background()); err != nil {
		t.Fatalf("validate OpenAPI document: %v", err)
	}
}

func TestEmbeddedOpenAPIAndSwaggerAssetsRemainValid(t *testing.T) {
	want, err := os.ReadFile(filepath.Join("docs", "openapi.yaml"))
	if err != nil {
		t.Fatalf("read checked-in OpenAPI spec: %v", err)
	}
	if !bytes.Equal(openAPISpec, want) {
		t.Fatal("embedded OpenAPI spec does not match docs/openapi.yaml")
	}

	for _, assetPath := range []string{"swagger-ui/index.html", "swagger-ui/swagger-initializer.js"} {
		asset, err := fs.ReadFile(swaggerUIFS, assetPath)
		if err != nil {
			t.Fatalf("read embedded asset %s: %v", assetPath, err)
		}
		if len(asset) == 0 {
			t.Fatalf("embedded asset %s is empty", assetPath)
		}
	}
}

func TestOpenAPIOperationsHaveOperationIDs(t *testing.T) {
	doc := loadOpenAPIDoc(t)

	var missing []string
	for path, pathItem := range doc.Paths.Map() {
		for method, operation := range pathItem.Operations() {
			if operation.OperationID == "" {
				missing = append(missing, strings.ToUpper(method)+" "+path)
			}
		}
	}
	if len(missing) == 0 {
		return
	}

	sort.Strings(missing)
	t.Fatalf("OpenAPI operations missing operationId:\n%s", strings.Join(missing, "\n"))
}

func TestOpenAPIReasonResponseMatchesSharedVocabulary(t *testing.T) {
	doc := loadOpenAPIDoc(t)

	reasonSchemaRef := doc.Components.Schemas["FailureReason"]
	if reasonSchemaRef == nil || reasonSchemaRef.Value == nil {
		t.Fatal("components.schemas.FailureReason is missing")
	}

	reasonResponseRef := doc.Components.Schemas["ReasonResponse"]
	if reasonResponseRef == nil || reasonResponseRef.Value == nil {
		t.Fatal("components.schemas.ReasonResponse is missing")
	}

	reasonPropertyRef := reasonResponseRef.Value.Properties["reason"]
	if reasonPropertyRef == nil {
		t.Fatal("components.schemas.ReasonResponse.properties.reason is missing")
	}
	if reasonPropertyRef.Ref != "#/components/schemas/FailureReason" {
		t.Fatalf("ReasonResponse.reason should reference FailureReason, got %q", reasonPropertyRef.Ref)
	}

	got := enumStrings(reasonSchemaRef.Value.Enum)
	want := make([]string, 0, len(handlers.CanonicalFailureReasons()))
	for _, reason := range handlers.CanonicalFailureReasons() {
		want = append(want, string(reason))
	}
	sort.Strings(got)
	sort.Strings(want)
	if !equalStringSlices(got, want) {
		t.Fatalf("FailureReason enum mismatch:\nwant: %v\ngot:  %v", want, got)
	}

	allowed := make(map[string]struct{}, len(got))
	for _, reason := range got {
		allowed[reason] = struct{}{}
	}

	if example, ok := reasonSchemaRef.Value.Example.(string); ok {
		if _, found := allowed[example]; !found {
			t.Fatalf("FailureReason example %q is not in the shared vocabulary", example)
		}
	}

	documentedReasons := documentedReasonValues(doc)
	for _, reason := range documentedReasons {
		if _, found := allowed[reason]; found {
			continue
		}
		t.Fatalf("documented reason %q is outside the shared vocabulary", reason)
	}
}

func loadOpenAPIDoc(t *testing.T) *openapi3.T {
	t.Helper()

	specPath := filepath.Join("docs", "openapi.yaml")
	loader := &openapi3.Loader{IsExternalRefsAllowed: true}
	doc, err := loader.LoadFromFile(specPath)
	if err != nil {
		t.Fatalf("load OpenAPI document (%s): %v", specPath, err)
	}
	return doc
}

func enumStrings(values []any) []string {
	out := make([]string, 0, len(values))
	for _, value := range values {
		text, ok := value.(string)
		if !ok {
			continue
		}
		out = append(out, text)
	}
	return out
}

func documentedReasonValues(doc *openapi3.T) []string {
	seen := map[string]struct{}{}
	for _, pathItem := range doc.Paths.Map() {
		for _, operation := range pathItem.Operations() {
			if operation.Responses == nil {
				continue
			}
			for _, responseRef := range operation.Responses.Map() {
				if responseRef == nil || responseRef.Value == nil {
					continue
				}
				for _, mediaRef := range responseRef.Value.Content {
					if mediaRef == nil {
						continue
					}
					recordReasonValue(seen, mediaRef.Example)
					for _, exampleRef := range mediaRef.Examples {
						if exampleRef == nil || exampleRef.Value == nil {
							continue
						}
						recordReasonValue(seen, exampleRef.Value.Value)
					}
				}
			}
		}
	}

	reasons := make([]string, 0, len(seen))
	for reason := range seen {
		reasons = append(reasons, reason)
	}
	sort.Strings(reasons)
	return reasons
}

func recordReasonValue(seen map[string]struct{}, payload any) {
	exampleMap, ok := payload.(map[string]any)
	if !ok {
		return
	}
	reason, ok := exampleMap["reason"].(string)
	if !ok || reason == "" {
		return
	}
	seen[reason] = struct{}{}
}

func equalStringSlices(left, right []string) bool {
	if len(left) != len(right) {
		return false
	}
	for i := range left {
		if left[i] != right[i] {
			return false
		}
	}
	return true
}

package handlers

const (
	ReasonMethodNotAllowed FailureReason = "METHOD_NOT_ALLOWED"
	ReasonInvalidRequest   FailureReason = "INVALID_REQUEST"

	// Canonical route-visible reasons for endpoints migrated onto the shared
	// API reason vocabulary.
	ReasonValidationFailed       FailureReason = "VALIDATION_FAILED"
	ReasonAuthenticationRequired FailureReason = "AUTHENTICATION_REQUIRED"
	ReasonAuthorizationDenied    FailureReason = "AUTHORIZATION_DENIED"
	ReasonPasswordChangeRequired FailureReason = "PASSWORD_CHANGE_REQUIRED"
	ReasonInvalidCredentials     FailureReason = "INVALID_CREDENTIALS"
	ReasonNotFound               FailureReason = "NOT_FOUND"
	ReasonMarketClosed           FailureReason = "MARKET_CLOSED"
	ReasonInsufficientBalance    FailureReason = "INSUFFICIENT_BALANCE"
	ReasonInvalidOutcome         FailureReason = "INVALID_OUTCOME"
	ReasonNoPosition             FailureReason = "NO_POSITION"
	ReasonInsufficientShares     FailureReason = "INSUFFICIENT_SHARES"
	ReasonDustCapExceeded        FailureReason = "DUST_CAP_EXCEEDED"
	ReasonInternalError          FailureReason = "INTERNAL_ERROR"

	// Legacy synonyms retained while older handlers are swept onto the shared
	// vocabulary.
	ReasonInvalidToken   FailureReason = "INVALID_TOKEN"
	ReasonUserNotFound   FailureReason = "USER_NOT_FOUND"
	ReasonMarketNotFound FailureReason = "MARKET_NOT_FOUND"
)

func CanonicalFailureReasons() []FailureReason {
	return []FailureReason{
		ReasonMethodNotAllowed,
		ReasonInvalidRequest,
		ReasonValidationFailed,
		ReasonAuthenticationRequired,
		ReasonAuthorizationDenied,
		ReasonPasswordChangeRequired,
		ReasonInvalidCredentials,
		ReasonNotFound,
		ReasonMarketClosed,
		ReasonInsufficientBalance,
		ReasonInvalidOutcome,
		ReasonNoPosition,
		ReasonInsufficientShares,
		ReasonDustCapExceeded,
		ReasonInternalError,
	}
}

func LegacyFailureReasons() []FailureReason {
	return []FailureReason{
		ReasonInvalidToken,
		ReasonUserNotFound,
		ReasonMarketNotFound,
	}
}

func AllFailureReasons() []FailureReason {
	reasons := CanonicalFailureReasons()
	return append(reasons, LegacyFailureReasons()...)
}

package failurereason

import (
	"errors"
	"net/http"
	"strings"

	"socialpredict/handlers"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

// FromAuthHTTPError maps auth boundary errors onto the shared public reason
// vocabulary used by migrated handlers.
func FromAuthHTTPError(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch {
	case err.StatusCode >= http.StatusInternalServerError:
		return handlers.ReasonInternalError
	case err.StatusCode == http.StatusUnauthorized:
		return handlers.ReasonAuthenticationRequired
	case err.StatusCode == http.StatusForbidden:
		if strings.EqualFold(err.Message, "Password change required") {
			return handlers.ReasonPasswordChangeRequired
		}
		return handlers.ReasonAuthorizationDenied
	case err.StatusCode == http.StatusNotFound:
		return handlers.ReasonNotFound
	default:
		return handlers.ReasonInternalError
	}
}

// LooksLikeValidation reports whether the error string appears to describe a
// caller-fixable validation or sanitization failure rather than an internal
// server problem.
func LooksLikeValidation(err error) bool {
	if err == nil {
		return false
	}

	lower := strings.ToLower(err.Error())
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required") ||
		strings.Contains(lower, "requirement") ||
		strings.Contains(lower, "unsupported") ||
		strings.Contains(lower, "mismatch")
}

// FromUserError maps users-domain failures onto the shared public reason
// vocabulary used by swept user/profile handlers.
func FromUserError(err error) (int, handlers.FailureReason) {
	switch {
	case err == nil:
		return http.StatusInternalServerError, handlers.ReasonInternalError
	case errors.Is(err, dusers.ErrUserNotFound):
		return http.StatusNotFound, handlers.ReasonNotFound
	case errors.Is(err, dusers.ErrInvalidUserData):
		return http.StatusBadRequest, handlers.ReasonValidationFailed
	case errors.Is(err, dusers.ErrInvalidCredentials):
		return http.StatusUnauthorized, handlers.ReasonInvalidCredentials
	case errors.Is(err, dusers.ErrUnauthorized):
		return http.StatusForbidden, handlers.ReasonAuthorizationDenied
	default:
		if LooksLikeValidation(err) {
			return http.StatusBadRequest, handlers.ReasonValidationFailed
		}
		return http.StatusInternalServerError, handlers.ReasonInternalError
	}
}
