// ListMarketsHandlerFactory creates an HTTP handler for listing markets with service injection
func ListMarketsHandlerFactory(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		handleListMarkets(w, r, svc)
	}
}

type listMarketsParams struct {
	status  string
	limit   int
	offset  int
	filters dmarkets.ListFilters
	page    dmarkets.Page
}

func parseListMarketsParams(r *http.Request) (listMarketsParams, error) {
	status, statusErr := normalizeStatusParam(r.URL.Query().Get("status"))
	if statusErr != nil {
		return listMarketsParams{}, statusErr
	}

	page := parseListPage(r)

	return listMarketsParams{
		status: status,
		limit:  page.Limit,
		offset: page.Offset,
		filters: dmarkets.ListFilters{
			Status:    status,
			CreatedBy: r.URL.Query().Get("created_by"),
			Limit:     page.Limit,
			Offset:    page.Offset,
		},
		page: page,
	}, nil
}

func parseListLimit(rawLimit string) int {
	return parseBoundedInt(rawLimit, 50, 1, 100)
}

func parseListOffset(rawOffset string) int {
	return parseBoundedInt(rawOffset, 0, 0, int(^uint(0)>>1))
}

func fetchMarkets(r *http.Request, svc dmarkets.ServiceInterface, params listMarketsParams) ([]*dmarkets.Market, error) {
	if params.filters.Status != "" {
		return fetchMarketsByStatus(r, svc, params)
	}
	return fetchAllMarkets(r, svc, params)
}

func writeListMarketsError(w http.ResponseWriter, err error) {
	message, statusCode := listMarketsErrorResponse(err)
	if statusCode == http.StatusInternalServerError {
		log.Printf("Error fetching markets: %v", err)
	}
	http.Error(w, message, statusCode)
}

func parseListPage(r *http.Request) dmarkets.Page {
	return dmarkets.Page{
		Limit:  parseListLimit(r.URL.Query().Get("limit")),
		Offset: parseListOffset(r.URL.Query().Get("offset")),
	}
}

func fetchMarketsByStatus(r *http.Request, svc dmarkets.ServiceInterface, params listMarketsParams) ([]*dmarkets.Market, error) {
	return svc.ListByStatus(r.Context(), params.filters.Status, params.page)
}

func fetchAllMarkets(r *http.Request, svc dmarkets.ServiceInterface, params listMarketsParams) ([]*dmarkets.Market, error) {
	return svc.ListMarkets(r.Context(), params.filters)
}

func writeListMarketsResponse(w http.ResponseWriter, r *http.Request, svc dmarkets.ServiceInterface, markets []*dmarkets.Market) error {
	response, err := buildListMarketsResponse(r, svc, markets)
	if err != nil {
		return err
	}
	return writeJSON(w, http.StatusOK, response)
}

func buildListMarketsResponse(r *http.Request, svc dmarkets.ServiceInterface, markets []*dmarkets.Market) (dto.ListMarketsResponse, error) {
	overviews, err := buildMarketOverviewResponses(r.Context(), svc, markets)
	if err != nil {
		log.Printf("Error building market overviews: %v", err)
		return dto.ListMarketsResponse{}, err
	}

	return dto.ListMarketsResponse{
		Markets: overviews,
		Total:   len(overviews),
	}, nil
}

func listMarketsErrorResponse(err error) (string, int) {
	switch err {
	case dmarkets.ErrInvalidInput:
		return "Invalid input parameters", http.StatusBadRequest
	case dmarkets.ErrUnauthorized:
		return "Unauthorized", http.StatusUnauthorized
	default:
		return "Error fetching markets", http.StatusInternalServerError
	}
}

func handleListMarkets(w http.ResponseWriter, r *http.Request, svc dmarkets.ServiceInterface) {
	log.Println("ListMarketsHandler: Request received")
	if r.Method != http.MethodGet {
		http.Error(w, "Method is not supported.", http.StatusMethodNotAllowed)
		return
	}

	params, parseErr := parseListMarketsParams(r)
	if parseErr != nil {
		http.Error(w, parseErr.Error(), http.StatusBadRequest)
		return
	}

	markets, err := fetchMarkets(r, svc, params)
	if err != nil {
		writeListMarketsError(w, err)
		return
	}

	if err := writeListMarketsResponse(w, r, svc, markets); err != nil {
		log.Printf("Error encoding list markets response: %v", err)
		http.Error(w, "Error encoding response", http.StatusInternalServerError)
	}
}

		return
	}

	if h.auth == nil {
		writeInternalFailure(w)
		return
	}

	// Get user for authorization
	user, httperr := h.auth.CurrentUser(r)
	if httperr != nil {
		writeAuthFailure(w, httperr)
		return
	}

	// Parse request body
	var req dto.ResolveMarketRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeInvalidRequest(w)
		return
	}

	// Call service
	if err := h.service.ResolveMarket(r.Context(), id, req.Resolution, user.Username); err != nil {
		writeMarketFailure(w, err)
		return
	}

	// Send success response
	w.WriteHeader(http.StatusNoContent)
}

// ListByStatus handles GET /markets/status/{status}
func (h *Handler) ListByStatus(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		writeMethodNotAllowed(w)
		return
	}

	statusValue, err := parseStatusFromRequest(r)
	if err != nil {
		writeInvalidRequest(w)
		return
	}

	page := parsePagination(r, 100)

	markets, err := h.fetchMarketsByStatus(r.Context(), statusValue, page)
	if err != nil {
		writeMarketFailure(w, err)
		return
	}

	// Convert to response DTOs
	overviews, err := buildMarketOverviewResponses(r.Context(), h.service, markets)
	if err != nil {
		writeMarketFailure(w, err)
		return
	}

	// Send response
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(dto.ListMarketsResponse{
		Markets: overviews,
		Total:   len(overviews),
	})
}

// GetDetails handles GET /markets/{id} with full market details
func (h *Handler) GetDetails(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		writeMethodNotAllowed(w)
		return
	}

	// Parse market ID from URL
	vars := mux.Vars(r)
	idStr := vars["id"]
	if idStr == "" {
		writeInvalidRequest(w)
		return
	}

	id, err := strconv.ParseInt(idStr, 10, 64)
	if err != nil {
		writeInvalidRequest(w)
		return
	}

	// Call service
	details, err := h.service.GetMarketDetails(r.Context(), id)
	if err != nil {
		writeMarketFailure(w, err)
		return
	}

	response := dto.MarketDetailsResponse{
		Market:             publicMarketResponseFromDomain(details.Market),
		Creator:            creatorResponseFromSummary(details.Creator),
		ProbabilityChanges: probabilityChangesToResponse(details.ProbabilityChanges),
		NumUsers:           details.NumUsers,
		TotalVolume:        details.TotalVolume,
		MarketDust:         details.MarketDust,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

// MarketLeaderboard handles GET /markets/{id}/leaderboard
func (h *Handler) MarketLeaderboard(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		writeMethodNotAllowed(w)
		return
	}

	id, err := parseMarketIDFromRequest(r)
	if err != nil {
		writeInvalidRequest(w)
		return
	}

	page := parsePagination(r, 100)

	// Call service
	leaderboard, err := h.service.GetMarketLeaderboard(r.Context(), id, page)
	if err != nil {
		writeMarketFailure(w, err)
		return
	}

	leaderRows := buildLeaderboardRows(leaderboard)

	response := dto.LeaderboardResponse{
		MarketID:    id,
		Leaderboard: leaderRows,
		Total:       len(leaderRows),
	}

	// Send response
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

// ProjectProbability handles GET /markets/{id}/projection
func (h *Handler) ProjectProbability(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		writeMethodNotAllowed(w)
		return
	}

	req, err := parseProjectionRequest(r)
	if err != nil {
		writeInvalidRequest(w)
		return
	}

	// Call service
	projection, err := h.service.ProjectProbability(r.Context(), req)
	if err != nil {
		writeMarketFailure(w, err)
		return
	}

	// Return response DTO
	response := dto.ProbabilityProjectionResponse{
		MarketID:             req.MarketID,
		CurrentProbability:   projection.CurrentProbability,
		ProjectedProbability: projection.ProjectedProbability,
		Amount:               req.Amount,
		Outcome:              req.Outcome,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

func parseStatusFromRequest(r *http.Request) (string, error) {
	vars := mux.Vars(r)
	if vars["status"] == "" {
		return "", errors.New("Status is required")
	}
	return normalizeStatusParam(vars["status"])
}

func parsePagination(r *http.Request, defaultLimit int) dmarkets.Page {
	limit := defaultLimit
	if limitStr := r.URL.Query().Get("limit"); limitStr != "" {
		if parsedLimit, err := strconv.Atoi(limitStr); err == nil && parsedLimit > 0 {
			limit = parsedLimit
		}
	}

	offset := 0
	if offsetStr := r.URL.Query().Get("offset"); offsetStr != "" {
		if parsedOffset, err := strconv.Atoi(offsetStr); err == nil && parsedOffset >= 0 {
			offset = parsedOffset
		}
	}

	return dmarkets.Page{
		Limit:  limit,
		Offset: offset,
	}
}

func (h *Handler) fetchMarketsByStatus(ctx context.Context, statusValue string, page dmarkets.Page) ([]*dmarkets.Market, error) {
	if statusValue == "" {
		filters := dmarkets.ListFilters{
			Status: "",
			Limit:  page.Limit,
			Offset: page.Offset,
		}
		return h.service.ListMarkets(ctx, filters)
	}
	return h.service.ListByStatus(ctx, statusValue, page)
}

func parseMarketIDFromRequest(r *http.Request) (int64, error) {
	vars := mux.Vars(r)
	idStr := vars["id"]
	if idStr == "" {
		idStr = vars["marketId"]
	}
	if idStr == "" {
		return 0, errors.New("Market ID is required")
	}

	return strconv.ParseInt(idStr, 10, 64)
